package com.pinova.api.assembler;import com.fasterxml.jackson.databind.*;import com.pinova.api.response.AdminProductResponse;import com.pinova.service.model.*;import org.springframework.stereotype.Component;
@Component public class AdminProductResponseAssembler{private final ObjectMapper json;public AdminProductResponseAssembler(ObjectMapper j){json=j;}public AdminProductResponse toResponse(AdminProductResult p){return new AdminProductResponse(String.valueOf(p.id()),String.valueOf(p.shopId()),String.valueOf(p.categoryId()),p.spuCode(),p.name(),p.summary(),p.productType(),p.mainImageKey(),p.status(),p.sortOrder(),p.version(),detail(p.detail()),p.skus().stream().map(s->new AdminProductResponse.Sku(String.valueOf(s.id()),s.skuCode(),s.specSummary(),s.salePriceFen(),s.inventoryMode(),s.mainImageKey(),s.barcode(),s.status(),s.sortOrder(),s.version())).toList(),p.media().stream().map(m->new AdminProductResponse.Media(String.valueOf(m.id()),m.spuId()==null?null:String.valueOf(m.spuId()),m.skuId()==null?null:String.valueOf(m.skuId()),m.mediaType(),m.mediaRole(),m.objectKey(),m.mimeType(),m.fileSizeBytes(),m.width(),m.height(),m.altText(),m.sortOrder(),m.status(),m.version())).toList());}private AdminProductResponse.Detail detail(AdminProductDetailResult d){if(d==null)return null;try{return new AdminProductResponse.Detail(d.schemaVersion(),json.readTree(d.documentJson()),d.packingList(),d.usageInstructions(),d.afterSalesNote(),d.version());}catch(Exception e){throw new IllegalStateException("商品详情 JSON 损坏",e);}}}
